      this.indirectDrawSlot,
      this.indirectDispatchSlot + 1,
      /** @type {StorageBuffer} */
      ic.numSplatsBuffer,
      /** @type {StorageBuffer} */
      ic.sortElementCountBuffer,
      sortIndirectInfo
