      /** @type {StorageBuffer} */
      projector.sortKeys,
      elementCount,
      roundedNumBits,
      this.indirectDispatchSlot + 1,
      /** @type {StorageBuffer} */
      ic.sortElementCountBuffer,
      void 0,
      false,
      true
